public class HeaderParser {
    private static final String DIRECTIVE_FILTER = "filter"; // NOI18N

    private final String headerName;
    private final Map<String, String> parameters = new HashMap<>();
    private final Map<String, String> directives = new HashMap<>();
    private final Map<String, String> filterValue = new HashMap<>();
    private final Feedback feedback;

    private String header;
    private int pos;
    private String directiveOrParameterName;
    private int contentStart;
    private String versionFilter;

    // static final ResourceBundle BUNDLE =
    // ResourceBundle.getBundle("org.graalvm.component.installer.persist.Bundle");

    public HeaderParser(String headerName, String header, Feedback feedback) {
        this.headerName = headerName;
        this.feedback = feedback;

        if (header != null) {
            // trim whitespaces;
            this.header = header.trim();
        } else {
            this.header = "";
        }
    }

    private MetadataException metaEx(String key, Object... args) {
        return new MetadataException(headerName, feedback.l10n(key, args));
    }

    public HeaderParser mustExist() throws MetadataException {
        if (header == null || header.isEmpty()) {
            throw metaEx("ERROR_HeaderMissing", headerName);
        }
        return this;
    }

    private static boolean isAlphaNum(char c) {
        return (c >= '0' && c <= '9') ||    // NOI18N
                        (c >= 'A' && c <= 'Z') ||    // NOI18N
                        (c >= 'a' && c <= 'z');      // NOI18N
    }

    private static boolean isToken(char c) {
        return isAlphaNum(c) || c == '_' || c == '-'; // NOI18N
    }

    private static boolean isExtended(char c) {
        return isToken(c) || c == '.';
    }

    public boolean getBoolean(Boolean defValue) {
        if (pos >= header.length()) {
            if (defValue == null) {
                throw metaEx("ERROR_HeaderMissing", headerName); // NOI18N
            }
            return defValue;
        } else {
            String s = header.substring(pos).trim().toLowerCase(Locale.ENGLISH);
            switch (s) {
                case "true": // NOI18N
                    return true;
                case "false": // NOI18N
                    return false;
            }
            throw metaEx("ERROR_HeaderInvalid", headerName, s); // NOI18N
        }
    }

    public String getContents(String defValue) {
        if (pos >= header.length()) {
            return defValue;
        } else {
            return header.substring(pos).trim();
        }
    }

    private void addFilterAttribute(String attrName, String value) {
        if (filterValue.put(attrName, value) != null) {
            throw metaErr("ERROR_DuplicateFilterAttribute");
        }
    }

    private boolean isEmpty() {
        return pos >= header.length();
    }

    public String parseSymbolicName() throws MetadataException {
        return parseNameOrNamespace(HeaderParser::isToken, "ERROR_MissingSymbolicName", "ERROR_InvalidSymbolicName", '.');
    }

    private char next() {
        return pos < header.length() ? header.charAt(pos++) : 0;
    }

    private void advance() {
        pos++;
    }

    private char ch() {
        return isEmpty() ? 0 : header.charAt(pos);
    }

    private String returnCut() {
        String s = cut();
        skipWhitespaces();
        return s;
    }

    private void skipWhitespaces() {
        while (!isEmpty()) {
            if (!Character.isWhitespace(ch())) {
                contentStart = pos;
                return;
            }
            advance();
        }
        contentStart = -1;
    }

    private void skipWithSemicolon() {
        skipWhitespaces();
        if (ch() == ';') {
            advance();
        }
        contentStart = -1;
    }

    private String cut() {
        return cut(0);
    }

    private String cut(int delim) {
        int e = pos - delim;
        return contentStart == -1 || contentStart >= e ? "" : header.substring(contentStart, e); // NOI18N
    }

    private void markContent() {
        contentStart = pos;
    }

    private String readExtendedParameter() throws MetadataException {
        skipWhitespaces();
        while (!isEmpty()) {
            char c = next();
            if (Character.isWhitespace(c)) {
                break;
            }
            if (!isExtended(c)) {
                throw metaEx("ERROR_InvalidParameterSyntax", directiveOrParameterName);
            }
        }
        String s = cut();
        skipWithSemicolon();
        return s;
    }

    private String readQuotedParameter() throws MetadataException {
        markContent();
        while (!isEmpty()) {
            char c = next();
            switch (c) {
                case '"':
                    return cut(1);
                case '\n':
                case '\r':
                case 0:
                    throw metaEx("ERROR_InvalidQuotedString");
                case '\\':
                    next();
                    break;
            }
        }
        throw metaEx("ERROR_InvalidQuotedString");
    }

    private String parseArgument() throws MetadataException {
        skipWhitespaces();
        char c = ch();
        if (c == ';') {
            throw metaEx("ERROR_MissingArgument", directiveOrParameterName);
        }
        if (c == '"') { // NOI18N
            advance();
            return readQuotedParameter();
        } else {
            return readExtendedParameter();
        }
    }

    private String parseNameOrNamespace(Predicate<Character> charAcceptor,
                    String missingKeyName, String invalidKeyName, char compDelimiter) throws MetadataException {
        if (header == null || isEmpty()) {
            throw metaEx(missingKeyName);
        }
        skipWhitespaces();
        boolean componentEmpty = true;
        while (!isEmpty()) {
            char c = ch();
            if (c == ';') {
                String s = cut();
                return s;
            }
            advance();
            if (c == compDelimiter) {
                if (componentEmpty) {
                    throw metaEx(invalidKeyName);
                }
                componentEmpty = true;
                continue;
            }
            if (Character.isWhitespace(c)) {
                break;
            }
            if (!charAcceptor.test(c)) {
                throw metaEx(invalidKeyName);
            }
            componentEmpty = false;
        }
        return returnCut();
    }

    private String parseNamespace() throws MetadataException {
        return parseNameOrNamespace(HeaderParser::isExtended, "ERROR_MissingCapabilityName", "ERROR_InvalidCapabilityName", (char) 0);
    }

    /**
     * Parses version at the current position.
     */
    public String version() throws MetadataException {
        int versionStart = -1;
        int partCount = 0;
        boolean partContents = false;
        if (isEmpty()) {
            throw metaErr("ERROR_InvalidVersion");
        }
        boolean dash = false;
        while (!isEmpty()) {
            char c = ch();

            if (Character.isWhitespace(c)) {
                if (versionStart != -1) {
                    break;
                }
                advance();
                continue;
            }

            if (c == ';') {
                break;
            }
            advance();
            if (c == '.') {
                if (++partCount > 3 || !partContents) {
                    throw metaErr("ERROR_InvalidVersion");
                }
                partContents = false;
                dash = false;
                continue;
            }
            if (partCount > 0 && partContents && c == '-') {
                dash = true;
                continue;
            }
            if (c >= '0' && c <= '9') {
                if (versionStart == -1) {
                    versionStart = pos - 1;
                }
            } else {
                if (partCount < 1) {
                    throw metaErr("ERROR_InvalidVersion");
                }
                boolean err = false;
                if (partCount >= 3 || dash) {
                    err = !isToken(c);
                } else {
                    err = true;
                }
                if (err) {
                    throw metaErr("ERROR_InvalidVersion");
                }
            }
            partContents = true;
        }
        String v = cut();
        skipWhitespaces();
        if (!isEmpty() || !partContents) {
            throw metaErr("ERROR_InvalidVersion");
        }

        return v;
    }

    private String readExtendedName() {
        skipWhitespaces();
        while (!isEmpty()) {
            char c = ch();
            if (isExtended(c)) {
                advance();
            } else if (Character.isWhitespace(c) || c == ':' || c == '=') {
                break;
            } else {
                throw metaEx("ERROR_InvalidParameterName");
            }
        }
        return returnCut();
    }

    private void parseParameters() {
        while (!isEmpty()) {
            String paramOrDirectiveName = readExtendedName();
            if (paramOrDirectiveName.isEmpty()) {
                throw metaEx("ERROR_InvalidParameterName");
            }
            directiveOrParameterName = paramOrDirectiveName;

            char c = ch();
            boolean dcolon = c == ':'; // NOI18N
            if (dcolon) {
                advance();
            }
            c = next();
            if (c != '=') { // NOI18N
                throw metaEx("ERROR_InvalidParameterSyntax", paramOrDirectiveName);
            }
            (dcolon ? directives : parameters).put(paramOrDirectiveName, parseArgument());
        }
    }

    private void replaceInputText(String text) {
        this.header = text;
        this.pos = 0;
    }

    private MetadataException metaErr(String key, Object... args) throws MetadataException {
        throw metaEx(key, args);
    }

    private MetadataException filterError() throws MetadataException {
        throw metaErr("ERROR_InvalidFilterSpecification");
    }

    private void parseFilterConjunction() {
        skipWhitespaces();
        char c = next();
        while (c == '(') {
            parseFilterContent();
            c = next();
        }
        if (c != ')') {
            throw filterError();
        }
    }

    private void parseFilterClause() {
        skipWhitespaces();
        int lastPos = -1;
        W: while (!isEmpty()) {
            char c = ch();
            if (Character.isWhitespace(c)) {
                if (lastPos == -1) {
                    lastPos = pos;
                }
                continue;
            }
            switch (c) {
                case '=':
                case '<':
                case '>':
                case '~':
                case '(':
                case ')':
                    break W;
            }
            lastPos = -1;
            advance();
        }

        String attributeName = returnCut();
        char c = next();
        if (c != '=') {
            throw metaErr("ERROR_UnsupportedFilterOperation");
        }
        c = ch();
        if (c == '*') {
            throw metaErr("ERROR_UnsupportedFilterOperation");
        }
        markContent();
        while (!isEmpty()) {
            c = next();
            if (c == ')') {
                addFilterAttribute(attributeName, cut(1));
                skipWhitespaces();
                return;
            }

            switch (c) {
                case '\\':
                    c = next();
                    if (c == 0) {
                        throw filterError();
                    }
                    break;
                case '*':
                    throw metaErr("ERROR_UnsupportedFilterOperation");
                case '(':
                case '<':
                case '>':
                case '~':
                case '=':
                    throw filterError();
            }
        }
        throw filterError();
    }

    private void parseFilterContent() {
        skipWhitespaces();
        char o = ch();
        if (o == '&') {
            advance();
            parseFilterConjunction();
        } else if (isExtended(o)) {
            parseFilterClause();
        } else {
            throw metaErr("ERROR_InvalidFilterSpecification");
        }
    }

    private void parseFilterSpecification() {
        skipWhitespaces();
        if (isEmpty()) {
            throw filterError();
        }
        char c = next();
        if (c == '(') {
            parseFilterContent();
            skipWhitespaces();
            if (!isEmpty()) {
                throw metaErr("ERROR_InvalidFilterSpecification");
            }
        } else {
            throw filterError();
        }
    }

    /**
     * Parses required capabilities string.
     *
     * org.graalvm; filter:="(&amp;(graalvm_version=0.32)(os_name=linux)(os_arch=amd64))"
     * 
     * @return graal capabilities
     * @throws MetadataException
     */
    public Map<String, String> parseRequiredCapabilities() {
        String namespace = parseNamespace();

        char c = next();
        if (c != ';' && c != 0) {
            throw metaErr("ERROR_InvalidFilterSpecification");
        }

        if (!BundleConstants.GRAALVM_CAPABILITY.equals(namespace)) {
            // unsupported capability
            throw new DependencyException(namespace, null, null, feedback.l10n("ERROR_UnknownCapability"));
        }
        parseParameters();

        if (!parameters.isEmpty()) {
            throw metaErr("ERROR_UnsupportedParameters");
        }
        versionFilter = directives.remove(DIRECTIVE_FILTER);
        if (!directives.isEmpty()) {
            throw metaErr("ERROR_UnsupportedDirectives");
        }
        if (versionFilter == null) {
            throw metaErr("ERROR_MissingVersionFilter");
        }

        // replace the input text, the rest of header will be ignored
        replaceInputText(versionFilter);
        parseFilterSpecification();

        return filterValue;
    }
},god_class

public class ServerFormatListPDU extends BaseElement {

    protected ClipboardState state;

    public ServerFormatListPDU(String id, ClipboardState state) {
        super(id);
        this.state = state;
    }

    @Override
    public void handleData(ByteBuffer buf, Link link) {
        if (verbose)
            System.out.println("[" + this + "] INFO: Data received: " + buf + ".");

        parseFormatNames(buf);
        buf.unref();

        // Automatically send request for text-based data to insert it into local
        // clipboard
        ClipboardDataFormat textFormat = ClipboardDataFormat.findBestTextFormat(state.serverClipboardDataFormats);
        if (textFormat != null) {
            // Send response: OK
            sendFormatListParseResponse(true);
            // Request data
            sendFormatDataRequest(textFormat);
        } else {
            // Send response: FAIL, we are not interested in this data
            sendFormatListParseResponse(false);
        }
    }

    /**
     * The Format Data Request PDU is sent by the recipient of the Format List
     * PDU. It is used to request the data for one of the formats that was listed
     * in the Format List PDU.
     */
    protected void sendFormatDataRequest(ClipboardDataFormat textFormat) {

        if (verbose)
            System.out.println("[" + this + "] INFO: Sending request for data in following format: " + textFormat + ".");

        // Store data format to parse server response later
        state.serverRequestedFormat = textFormat;

        ByteBuffer buf = new ByteBuffer(12, true);

        // Type
        buf.writeShortLE(ServerClipRdrChannelRouter.CB_FORMAT_DATA_REQUEST);
        // Message flags
        buf.writeShortLE(0);
        // Length
        buf.writeIntLE(4);

        // ID of chosen format
        buf.writeIntLE(textFormat.id);

        buf.trimAtCursor();

        pushDataToPad(STDOUT, buf);
    }

    /**
     * The Format List Response PDU is sent as a reply to the Format List PDU. It
     * is used to indicate whether processing of the Format List PDU was
     * successful.
     *
     * @param b
     */
    protected void sendFormatListParseResponse(boolean ok) {
        ByteBuffer buf = new ByteBuffer(8, true);

        // Type
        buf.writeShortLE(ServerClipRdrChannelRouter.CB_FORMAT_LIST_RESPONSE);
        // Message flags
        buf.writeShortLE((ok) ? ServerClipRdrChannelRouter.CB_RESPONSE_OK : ServerClipRdrChannelRouter.CB_RESPONSE_FAIL);
        // Length
        buf.writeIntLE(0);

        buf.trimAtCursor();

        pushDataToPad(STDOUT, buf);
    }

    protected void parseFormatNames(ByteBuffer buf) {

        // Set will not be modified after creation, so there is no need to make it
        // synchronous.
        Map<Object, ClipboardDataFormat> formats = new HashMap<Object, ClipboardDataFormat>();

        while (buf.cursor < buf.length) {
            int id = buf.readSignedIntLE();

            String name;
            if (state.serverUseLongFormatNames) {
                // Long format names in Unicode
                name = buf.readVariableWideString(RdpConstants.CHARSET_16);
            } else {
                Boolean asciiNames = (Boolean)buf.getMetadata(ServerClipRdrChannelRouter.ASCII_NAMES);

                if (asciiNames != null && asciiNames) {
                    // Short format names in ASCII
                    name = buf.readString(32, RdpConstants.CHARSET_8);
                } else {
                    // Short format names in Unicode
                    name = buf.readString(32, RdpConstants.CHARSET_16);
                }

            }

            // Store format in map by both ID and name (if name is not empty)
            formats.put(id, new ClipboardDataFormat(id, name));
            if (name.length() > 0)
                formats.put(name, new ClipboardDataFormat(id, name));
        }

        if (verbose)
            System.out.println("Server supports following formats for clipboard data: " + formats.values().toString() + ".");

        state.serverClipboardDataFormats = formats;
    }

    /**
     * Example.
     */
    public static void main(String[] args) {
        // System.setProperty("streamer.Link.debug", "true");
        System.setProperty("streamer.Element.debug", "true");
        // System.setProperty("streamer.Pipeline.debug", "true");

        /* @formatter:off */
        byte[] packet = new byte[] {
                0x02, 0x00,  //  CLIPRDR_HEADER::msgType = CB_FORMAT_LIST (2)
                0x00, 0x00,  //  CLIPRDR_HEADER::msgFlags = 0
                (byte) 0xe0, 0x00, 0x00, 0x00,  //  CLIPRDR_HEADER::dataLen = 0xe0 = 224 bytes

                (byte) 0x8a, (byte) 0xc0, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 0xc08a = 49290
                0x52, 0x00, 0x69, 0x00, 0x63, 0x00, 0x68, 0x00, 0x20, 0x00, 0x54, 0x00, 0x65, 0x00, 0x78, 0x00, 0x74, 0x00, 0x20, 0x00, 0x46, 0x00, 0x6f, 0x00, 0x72, 0x00, 0x6d, 0x00, 0x61, 0x00, 0x74, 0x00, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatName = "Rich Text Format"

                0x45, (byte) 0xc1, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 0xc145 = 49477
                0x52, 0x00, 0x69, 0x00, 0x63, 0x00, 0x68, 0x00, 0x20, 0x00, 0x54, 0x00, 0x65, 0x00, 0x78, 0x00,
                0x74, 0x00, 0x20, 0x00, 0x46, 0x00, 0x6f, 0x00, 0x72, 0x00, 0x6d, 0x00, 0x61, 0x00, 0x74, 0x00,
                0x20, 0x00, 0x57, 0x00, 0x69, 0x00, 0x74, 0x00, 0x68, 0x00, 0x6f, 0x00, 0x75, 0x00, 0x74, 0x00,
                0x20, 0x00, 0x4f, 0x00, 0x62, 0x00, 0x6a, 0x00, 0x65, 0x00, 0x63, 0x00, 0x74, 0x00, 0x73, 0x00,
                0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatName = "Rich Text Format Without Objects"

                0x43, (byte) 0xc1, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 0xc143 = 49475
                0x52, 0x00, 0x54, 0x00, 0x46, 0x00, 0x20, 0x00, 0x41, 0x00, 0x73, 0x00, 0x20, 0x00, 0x54, 0x00,
                0x65, 0x00, 0x78, 0x00, 0x74, 0x00, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatName = "RTF As Text"

                0x01, 0x00, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 1
                0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatName = ""

                0x0d, 0x00, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 0x0d = 13
                0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatName = ""

                0x04, (byte) 0xc0, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 0xc004 = 49156
                0x4e, 0x00, 0x61, 0x00, 0x74, 0x00, 0x69, 0x00, 0x76, 0x00, 0x65, 0x00, 0x00, 0x00,  //  "Native"

                0x0e, (byte) 0xc0, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 0xc00e = 49166
                0x4f, 0x00, 0x62, 0x00, 0x6a, 0x00, 0x65, 0x00, 0x63, 0x00, 0x74, 0x00, 0x20, 0x00, 0x44, 0x00,
                0x65, 0x00, 0x73, 0x00, 0x63, 0x00, 0x72, 0x00, 0x69, 0x00, 0x70, 0x00, 0x74, 0x00, 0x6f, 0x00,
                0x72, 0x00, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatName = "Object Descriptor"

                0x03, 0x00, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 3
                0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatName = ""

                0x10, 0x00, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 16
                0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatName = ""

                0x07, 0x00, 0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatId = 7
                0x00, 0x00,  //  CLIPRDR_LONG_FORMAT_NAME::formatName = ""
        };
        /* @formatter:on */

        MockSource source = new MockSource("source", ByteBuffer.convertByteArraysToByteBuffers(packet));
        Element router = new ServerClipRdrChannelRouter("router");
        ClipboardState state = new ClipboardState();
        state.serverUseLongFormatNames = true;
        Element format_list = new ServerFormatListPDU("format_list", state);

        Element sink = new MockSink("sink", ByteBuffer.convertByteArraysToByteBuffers(new byte[] {
                // Format List Response PDU
                0x03, 0x00, // CLIPRDR_HEADER::msgType = CB_FORMAT_LIST_RESPONSE (3)
                0x01, 0x00, // CLIPRDR_HEADER::msgFlags = 0x0001 = CB_RESPONSE_OK
                0x00, 0x00, 0x00, 0x00, // CLIPRDR_HEADER::dataLen = 0 bytes
        }, new byte[] {
                // Format Data Request PDU
                0x04, 0x00, // CLIPRDR_HEADER::msgType = CB_FORMAT_DATA_REQUEST (4)
                0x00, 0x00, // CLIPRDR_HEADER::msgFlags = 0
                0x04, 0x00, 0x00, 0x00, // CLIPRDR_HEADER::dataLen = 4 bytes
                0x0d, 0x00, 0x00, 0x00, // CLIPRDR_FORMAT_DATA_REQUEST::requestedFormatId
                // = 0x0d
        }));

        Pipeline pipeline = new PipelineImpl("test");
        pipeline.add(source, router, format_list, sink);
        pipeline.link("source", "router >format_list", "format_list", "sink");
        pipeline.runMainLoop("source", STDOUT, false, false);

        // Check state
        if (!(state.serverClipboardDataFormats.containsKey(49475) && state.serverClipboardDataFormats.containsKey("Rich Text Format")))
            throw new RuntimeException("Server format list packet parsed incorrectly.");

    }

