private static class DoubleNotPackedWriters extends AbstractPrimitiveWriters<double[], Double> {
    public DoubleNotPackedWriters(Field protoField) {
      super(protoField);

      primitiveArrayWriter = (OutputEx output, double[] array) -> {
        for (double element : array) {
          output.writeDouble(tag, tagSize, element);
        }
      };

      arrayWriter = (OutputEx output, Double[] array) -> {
        for (Double element : array) {
          if (element != null) {
            output.writeDouble(tag, tagSize, element);
            continue;
          }

          ProtoUtils.throwNotSupportNullElement(protoField);
        }
      };

      collectionWriter = (OutputEx output, Collection<Double> collection) -> {
        for (Double element : collection) {
          if (element != null) {
            output.writeDouble(tag, tagSize, element);
            continue;
          }

          ProtoUtils.throwNotSupportNullElement(protoField);
        }
      };

      stringArrayWriter = (OutputEx output, String[] array) -> {
        for (String element : array) {
          if (element != null) {
            double parsedValue = Double.parseDouble(element);
            output.writeDouble(tag, tagSize, parsedValue);
            continue;
          }

          ProtoUtils.throwNotSupportNullElement(protoField);
        }
      };
    }
  },god_class

public class SortedByFacetOnCollectionFromLayoutProperties extends SortedByFacetAbstract {

    public static SortedByFacet create(Properties properties, FacetHolder holder) {
        final Class sortedBy = sortedBy(properties);
        return sortedBy != null? new SortedByFacetOnCollectionFromLayoutProperties(sortedBy, holder): null;
    }

    private SortedByFacetOnCollectionFromLayoutProperties(Class<? extends Comparator<?>> sortedBy, FacetHolder holder) {
        super(sortedBy, holder);
    }

    private static Class<?> sortedBy(Properties properties) {
        if(properties == null) {
            return null;
        }
        String sortedBy = Strings.emptyToNull(properties.getProperty("sortedBy"));
        if (sortedBy == null) {
            return null;
        }
        final Class<?> sortedByClass = ClassUtil.forName(sortedBy);
        if(sortedByClass == Comparator.class) {
            return null;
        }
        return sortedByClass;
    }

