						 g.setFont(pleaseWaitFont);
						 g.setColor(java.awt.Color.black);
						 y += 2;
						 g.drawString(str1, 2 + (getWidth()/2) - (fm.stringWidth(str1)/2), y + fm.getAscent());
						 y += fm.getHeight();
						 g.drawString(str2, 2 + (getWidth()/2) - (fm.stringWidth(str2)/2), y + fm.getAscent());
						 y += 2*fm.getHeight();
