	private Object timerLocks = new Object();
	private void cancelHideTimer()
	{
		synchronized (timerLocks)
		{
			if (hideTimer != null)
				hideTimer.cancel();
		}
	}
	public void resetHideTimer()
	{
		synchronized (timerLocks)
		{
			if (hideTimer != null)
				hideTimer.cancel();
			myConn.addTimerTask(hideTimer = new HideTimerTask(), 5000, 0);
		}
	}
