public final class Scanner implements Iterator<String>, Closeable {

    private static final Map<String, Pattern> CACHE = new LinkedHashMap<String, Pattern>() {
        @Override
        protected boolean removeEldestEntry(Entry<String, Pattern> eldest) {
            return size() >= 7;
        }
    };

    private static final String WHITESPACE_PATTERN = "\\s+";

    private static final String FIND_ANY_PATTERN = "(?s).*";

    private static final int BUFFER_SIZE = 1024;

    private Readable source;
    private Pattern delimPattern;
    private Matcher matcher;
    private CharBuffer buf;
    private int position;
    private boolean inputExhausted;
    private boolean needInput;
    private boolean skipped;
    private int savedPosition = -1;
    private boolean closed;
    private IOException lastIOException;

    public Scanner(InputStream source, String charsetName, String pattern) {
        this(new InputStreamReader(Objects.requireNonNull(source, "source"), toDecoder(charsetName)), cachePattern(pattern));
    }

    public Scanner(File source, String charsetName, String pattern) throws FileNotFoundException {
        this(new FileInputStream(Objects.requireNonNull(source, "source")).getChannel(), charsetName, pattern);
    }

    public Scanner(String source, String pattern) {
        this(new StringReader(Objects.requireNonNull(source, "source")), cachePattern(pattern));
    }

    public Scanner(ReadableByteChannel source, String charsetName, String pattern) {
        this(Channels.newReader(Objects.requireNonNull(source, "source"), toDecoder(charsetName), -1), cachePattern(pattern));
    }

    public Scanner(Readable source, String pattern) {
        this(Objects.requireNonNull(source, "source"), cachePattern(pattern));
    }

    private Scanner(Readable source, Pattern pattern) {
        this.source = source;
        delimPattern = pattern != null ? pattern : cachePattern(WHITESPACE_PATTERN);
        buf = CharBuffer.allocate(BUFFER_SIZE);
        buf.limit(0);
        matcher = delimPattern.matcher(buf);
        matcher.useTransparentBounds(true);
        matcher.useAnchoringBounds(false);
    }

    private static CharsetDecoder toDecoder(String charsetName) {
        try {
            Charset cs = charsetName != null ? Charset.forName(charsetName) : Charset.defaultCharset();
            return cs.newDecoder();
        } catch (IllegalCharsetNameException | UnsupportedCharsetException e) {
            throw new IllegalArgumentException(e);
        }
    }

    public boolean hasNext() {
        checkClosed();
        saveState();
        while (!inputExhausted) {
            if (hasTokenInBuffer()) {
                revertState();
                return true;
            }
            readMore();
        }
        boolean result = hasTokenInBuffer();
        revertState();
        return result;
    }

    public String next() {
        checkClosed();
        while (true) {
            String token = getCompleteTokenInBuffer();
            if (token != null) {
                skipped = false;
                return token;
            }
            if (needInput) {
                readMore();
            } else {
                throwFor();
            }
        }
    }

    private void saveState() {
        savedPosition = position;
    }

    private void revertState() {
        position = savedPosition;
        savedPosition = -1;
        skipped = false;
    }

    private void readMore() {
        if (buf.limit() == buf.capacity()) {
            expandBuffer();
        }
        int p = buf.position();
        buf.position(buf.limit());
        buf.limit(buf.capacity());
        int n;
        try {
            n = source.read(buf);
        } catch (IOException ioe) {
            lastIOException = ioe;
            n = -1;
        }
        if (n == -1) {
            inputExhausted = true;
            needInput = false;
        } else if (n > 0) {
            needInput = false;
        }
        buf.limit(buf.position());
        buf.position(p);
    }

    private void expandBuffer() {
        int offset = savedPosition == -1 ? position : savedPosition;
        buf.position(offset);
        if (offset > 0) {
            buf.compact();
            translateSavedIndexes(offset);
            position -= offset;
            buf.flip();
        } else {
            int newSize = buf.capacity() * 2;
            CharBuffer newBuf = CharBuffer.allocate(newSize);
            newBuf.put(buf);
            newBuf.flip();
            translateSavedIndexes(offset);
            position -= offset;
            buf = newBuf;
            matcher.reset(buf);
        }
    }

    private void translateSavedIndexes(int offset) {
        if (savedPosition != -1) {
            savedPosition -= offset;
        }
    }

    private void throwFor() {
        skipped = false;
        if (inputExhausted && position == buf.limit()) {
            throw new NoSuchElementException();
        } else {
            throw new InputMismatchException();
        }
    }

    private boolean hasTokenInBuffer() {
        matcher.usePattern(delimPattern);
        matcher.region(position, buf.limit());
        if (matcher.lookingAt()) {
            position = matcher.end();
        }
        return position != buf.limit();
    }

    private String getCompleteTokenInBuffer() {
        matcher.usePattern(delimPattern);
        if (!skipped) {
            matcher.region(position, buf.limit());
            if (matcher.lookingAt()) {
                if (matcher.hitEnd() && !inputExhausted) {
                    needInput = true;
                    return null;
                }
                skipped = true;
                position = matcher.end();
            }
        }
        if (position == buf.limit()) {
            if (inputExhausted) {
                return null;
            }
            needInput = true;
            return null;
        }
        matcher.region(position, buf.limit());
        boolean foundNextDelim = matcher.find();
        if (foundNextDelim && (matcher.end() == position)) {
            foundNextDelim = matcher.find();
        }
        if (foundNextDelim) {
            if (matcher.requireEnd() && !inputExhausted) {
                needInput = true;
                return null;
            }
            int tokenEnd = matcher.start();
            matcher.usePattern(cachePattern(FIND_ANY_PATTERN));
            matcher.region(position, tokenEnd);
            if (matcher.matches()) {
                String s = matcher.group();
                position = matcher.end();
                return s;
            } else {
                return null;
            }
        }
        if (inputExhausted) {
            matcher.usePattern(cachePattern(FIND_ANY_PATTERN));
            matcher.region(position, buf.limit());
            if (matcher.matches()) {
                String s = matcher.group();
                position = matcher.end();
                return s;
            }
            return null;
        }
        needInput = true;
        return null;
    }

    private void checkClosed() {
        if (closed) {
            throw new IllegalStateException();
        }
    }

    public void close() throws IOException {
        if (!closed) {
            closed = true;
            if (source instanceof Closeable) {
                try {
                    ((Closeable) source).close();
                } catch (IOException e) {
                    lastIOException = e;
                }
            }
        }
        if (lastIOException != null) {
            throw lastIOException;
        }
    }

    private static Pattern cachePattern(String pattern) {
        if (pattern == null) {
            return null;
        }
        return CACHE.computeIfAbsent(pattern, Pattern::compile);
    }

},god_class

public class Subchannel extends Pipe {
	/**
	 * <p>
	 * Number of fuel rods contained within.
	 * </p>
	 * 
	 */
	private int numRods;

	/**
	 * <p>
	 * Diameter of the subchannel fuel rods (this assumes uniform rod sizes).
	 * </p>
	 * 
	 */
	private double rodDiameter;

	/**
	 * <p>
	 * Pitch of the fuel rod bundle (distance between adjacent rod centers).
	 * </p>
	 * 
	 */
	private double pitch;

	/**
	 * <p>
	 * Nullary constructor.
	 * </p>
	 * 
	 */
	public Subchannel() {

		// Set the name, description and ID.
		setName("Subchannel 1");
		setDescription("A subchannel plant component for reactors");
		setId(1);

		// Set the default number of rods, rod diameter and pitch.
		setNumRods(1);
		setRodDiameter(1.0);
		setPitch(1.5);
		// Note: Pitch must always be set after diameter, as setPitch method
		// checks that pitch >= rodDiameter.

		return;
	}

	/**
	 * <p>
	 * Parameterized constructor.
	 * </p>
	 * 
	 * @param numRods
	 *            <p>
	 *            Number of rods contained.
	 *            </p>
	 * @param rodDiameter
	 *            <p>
	 *            Diameter of the (uniformly-sized) fuel rods.
	 *            </p>
	 * @param pitch
	 *            <p>
	 *            Pitch of the fuel rods.
	 *            </p>
	 */
	public Subchannel(int numRods, double rodDiameter, double pitch) {

		// Set the name, description and ID.
		setName("Subchannel 1");
		setDescription("A subchannel plant component for reactors");
		setId(1);

		// Set the default number of rods, rod diameter and pitch.
		setNumRods(numRods);
		setRodDiameter(rodDiameter);
		setPitch(pitch);

		return;
	}

	/**
	 * @return the numRods
	 */
	public int getNumRods() {
		return numRods;
	}

	/**
	 * @param numRods
	 *            the numRods to set
	 */
	public void setNumRods(int numRods) {

		// Check the input is valid.
		if (numRods >= 1) {
			this.numRods = numRods;
		} else {
			throw new InvalidParameterException("Subchannel error: The number "
					+ "of rods must greater than or equal to 1.");
		}
		return;
	}

	/**
	 * @return the rodDiameter
	 */
	public double getRodDiameter() {
		return rodDiameter;
	}

	/**
	 * @param rodDiameter
	 *            the rodDiameter to set
	 */
	public void setRodDiameter(double rodDiameter) {

		// Check the input is valid.
		if (rodDiameter > 0) {
			this.rodDiameter = rodDiameter;
		} else {
			throw new InvalidParameterException("Subchannel error: The rod "
					+ "diameter must be non-negative.");
		}
		return;
	}

	/**
	 * @return the pitch
	 */
	public double getPitch() {
		return pitch;
	}

	/**
	 * @param pitch
	 *            the pitch to set
	 */
	public void setPitch(double pitch) {

		// Check that the input is valid.
		if (pitch >= rodDiameter) {
			this.pitch = pitch;
		} else {
			throw new InvalidParameterException("Subchannel error: The rod "
					+ "pitch cannot be smaller than the rod diameter.");
		}
	}

	/**
	 * <p>
	 * Performs an equality check between two Objects.
	 * </p>
	 * 
	 * @param otherObject
	 *            <p>
	 *            The other Object to compare against.
	 *            </p>
	 * @return <p>
	 *         Returns true if the two objects are equal, otherwise false.
	 *         </p>
	 */
	@Override
	public boolean equals(Object otherObject) {

		// By default, the objects are not equivalent.
		boolean equals = false;

		// Check the reference.
		if (this == otherObject) {
			equals = true;
		}
		// Check the information stored in the other object.
		else if (otherObject != null && otherObject instanceof Subchannel) {

			// Cast the other object.
			Subchannel component = (Subchannel) otherObject;

			// Compare all the variables. (Save the biggest for last; Java
			// should
			// short-circuit the logical operators as soon as a mismatch is
			// found)
			equals = (super.equals(component) && numRods == component.numRods
					&& rodDiameter == component.rodDiameter && pitch == component.pitch);
		}

		return equals;
	}

	/**
	 * <p>
	 * Performs a deep copy and returns a newly instantiated Object.
	 * </p>
	 * 
	 * @return <p>
	 *         The newly instantiated Object.
	 *         </p>
	 */
	@Override
	public Object clone() {

		// Initialize a new object.
		Subchannel object = new Subchannel();

		// Copy the contents from this one.
		object.copy(this);

		// Return the newly instantiated object.
		return object;
	}

	/**
	 * <p>
	 * Deep copies the contents of otherObject.
	 * </p>
	 * 
	 * @param otherObject
	 *            <p>
	 *            The other object to copy the contents from.
	 *            </p>
	 */
	public void copy(Subchannel otherObject) {

		// Check the otherObject is valid.
		if (otherObject == null) {
			return;
		}
		// Copy the other object.
		super.copy(otherObject);
		numRods = otherObject.numRods;
		rodDiameter = otherObject.rodDiameter;
		pitch = otherObject.pitch;

		return;
	}

	/**
	 * <p>
	 * Returns the hashCode of the object.
	 * </p>
	 * 
	 * @return <p>
	 *         The hashCode of the Object.
	 *         </p>
	 */
	@Override
	public int hashCode() {

		// Call the super's hashCode.
		int hash = super.hashCode();

		// Add local hashes.
		hash = 31 * hash + numRods;
		hash = 31 * hash + new Double(rodDiameter).hashCode();
		hash = 31 * hash + new Double(pitch).hashCode();

		return hash;
	}

	/**
	 * <p>
	 * Accepts PlantComponentVisitors to reveal the type of a PlantComponent.
	 * </p>
	 * 
	 * @param visitor
	 *            <p>
	 *            The PlantComponent's visitor.
	 *            </p>
	 */
	@Override
	public void accept(IPlantComponentVisitor visitor) {

		// Only accept valid visitors.
		if (visitor != null) {
			visitor.visit(this);
		}
		return;
	}
},god_class

